SELECT count(*) FROM title, kind_type, movie_info, cast_info, movie_companies, movie_keyword, company_type, company_name WHERE title.kind_id = kind_type.id AND movie_info.movie_id = title.id AND cast_info.movie_id = title.id AND movie_companies.movie_id = title.id AND movie_keyword.movie_id = title.id AND movie_companies.company_type_id = company_type.id AND movie_companies.company_id = company_name.id;